import{_ as l,I as a,o as i,c,j as e,a as o,J as n}from"./chunks/framework.DYZFTu11.js";const f=JSON.parse('{"title":"《α星篇·完结篇2：往日种种...》","description":"","frontmatter":{},"headers":[],"relativePath":"zh_cn/novels/shuangxingluji/chapter-13.md","filePath":"zh_cn/novels/shuangxingluji/chapter-13.md","lastUpdated":1773498699000}'),p={name:"zh_cn/novels/shuangxingluji/chapter-13.md"};function d(u,t,h,g,_,m){const s=a("NolebaseGitContributors"),r=a("NolebaseGitChangelog");return i(),c("div",null,[t[0]||(t[0]=e("h1",{id:"《α星篇·完结篇2-往日种种-》",tabindex:"-1"},[e("strong",null,"《α星篇·完结篇2：往日种种...》"),o(),e("a",{class:"header-anchor",href:"#《α星篇·完结篇2-往日种种-》","aria-label":"Permalink to “《α星篇·完结篇2：往日种种...》”"},"​")],-1)),t[1]||(t[1]=e("p",null,[e("strong",null,"《α星篇·完结篇2：往日种种...》"),o(' 冰冷的金属走廊仿佛一条被遗忘了亿万年的深海巨兽的食道，深邃、冗长，望不见尽头。星溯、叶子以及那位始终沉默如石像的士兵，正被这巨兽缓缓吞入腹中。墙壁上，应急指示灯的微光如同垂死者最后的呼吸，忽明忽暗，挣扎着将惨绿的光芒投射在抛光得能映出人影的合金地面上。三人的影子被拉扯得奇形怪状，随着他们深一脚浅一脚的步伐，在地面与墙壁之间如同鬼魅般扭曲、摇曳、舞蹈，仿佛是这基地深处囚禁的无数亡魂，正无声地攀附在他们身上。 空气中弥漫着一股难以言喻的复杂气味——那是高压设备漏出的臭氧、经年累月挥发不散的消毒水、以及金属和尘埃在时光中缓慢腐朽的味道，混合成了这片被文明遗弃的角落所独有的、令人胸闷的“芬芳”。 这里曾是α星最负盛名的，也是离诅咒之地最近的诅咒之地专项科研基地，是财团科技树上最璀璨的明珠之一。无数顶尖的智慧头脑曾在这里燃烧自己，为了财团那永无止境的野心与欲望，将一个个疯狂，残暴的构想变为现实。而今，这走廊里只剩下他们三人的脚步声在死寂中回荡，空旷得让星溯几乎能听到自己血液流过耳膜的“嗡嗡”声，以及那擂鼓般的心跳。 “你不觉得这里……太安静了吗？”星溯终于无法忍受这几乎要将人逼疯的寂静，她下意识地向叶子身边靠了靠，仿佛对方身上那股天不怕地不怕的气场能分给她一些，声音压得极低，如同耳语，“安静得有点过头了。我总感觉……有什么东西在后面，就在我们刚刚走过的黑暗里盯着我们，就像……就像2030年代的老式恐怖片里，主角一回头怪物就贴脸上的那种。” 叶子用眼角的余光瞥了她一眼，那眼神里明晃晃地写着“你又开始了”的无奈，但她紧握着突击步枪的手，指关节却因为用力而微微泛白。“我说大小姐，咱能别自己吓自己吗？财团撤离的时候向来有‘三光政策’——资料带光，设备搬光，活物杀光。这里应该早就被清理得比你的脸还干净了，”她毫不留情地吐槽着，脚步却不自觉地加快了半拍，与星溯的距离也拉近了些许。 “而且，”她继续说道，语气里带着几分刻意营造的轻松，“这个地方是整个基地的最底层，唯一的入口就是我们进来的那个通风管，隐蔽到你要让我再进一次，我都不知道往哪走的。那些长毛的臭灵裔想找到这里，除非它们开了全图透视挂。至于没清理干净留下的实验品……都这么多天过去了，就算真有什么‘小可爱’没被处理干净，现在估计也早就饿死了……吧？” 最后那个拖长了音、充满不确定性的“吧”字，像一只无形的手，将星溯刚刚想放下的心又提到了嗓子眼。她识趣地闭上了嘴，不敢再用自己的乌鸦嘴去挑战墨菲定律，只能在心里默默祈祷叶子的判断是百分之百正确的。 幸运的是，这段令人毛骨悚然的旅程并没有按B级恐怖片的剧本上演任何经典桥段。当那位沉默的士兵在一扇厚重得如同金库大门的气密门前停下，并在控制面板上输入了一长串复杂的指令后，伴随着沉闷的液压声，那扇门缓缓向一侧滑开。 一瞬间，刺眼夺目的光芒如决堤的洪水般汹涌而入，瞬间驱散了走廊里所有的阴森与黑暗。一个无比开阔的巨大空间毫无征兆地展现在她们眼前。穹顶高得几乎望不见尽头，无数探照灯将整个空间照得亮如白昼。四周如同钢铁丛林般陈列着各种复杂的维护设备、龙门吊和巨大的机械臂，而在这一片冰冷的钢铁造物簇拥的中央，静静地停泊着一艘足以让任何机械爱好者、军事迷乃至艺术家都为之疯狂的飞船。 它通体呈现出一种深邃的、近乎能吸收一切光线的哑光黑色涂层，却能在某些特定的角度下，隐隐反射出星云般的幽蓝色光泽，仿佛它的外壳之下，囚禁着一片浓缩的宇宙。船体的线条流畅、优雅到了极致，充满了未来主义的暴力美学，从舰首的锐利冲角到舰尾的矢量喷口，你看不到任何传统意义上的拼接缝隙或铆钉，仿佛它并非由零件组装而成，而是由一块完整的晶体，被某位神明亲手雕琢而成的艺术品。这艘船的设计理念与制造工艺，显然已经远远超越了当前星系内公开的任何科技水平。 “幽影号……”叶子的嘴唇无意识地翕动着，吐出了这个她曾在一些权限等级极高的绝密资料中惊鸿一瞥的代号。财团倾尽整个星系的资源，秘密打造的、独一无二的次世代隐形突击舰，传说中它甚至从未真正服役过，是财团藏得最深、最锋利的一张王牌。 飞船的登机舷梯已经放下，尼尔德正站在舷梯口，与一个男人激烈地讨论着什么。那个男人穿着一身沾满了油污和灰尘的工程师制服，脸上黑一块白一块，像是刚从某个废弃了百年的烟囱里钻出来。然而，他那双深陷在眼窝里的眼睛却锐利如鹰隼，闪烁着一种不容置疑的专业、自信与狂热。 “哟，尼尔德！”叶子远远地挥了挥手，她清脆的声音在这空旷得过分的船库里荡起一连串清晰的回音。 尼尔德闻声回头，对那位工程师做了个暂停的手势，脸上露出一丝如释重负的欣慰笑容。“叶子，星溯，你们总算来了，我还担心你们在路上会遇到麻烦。”他侧过身，指了指身旁那位不修边幅的男人，介绍道：“这位是洛克，前α星防卫军第444‘地鼠’师工程团团长，现在是我们这支幸存者小队当之无愧的总工程师。” 洛克只是朝着她们粗略地抬了抬下巴，算是打过招呼，随即又迫不及待地转过头去，用手里的数据终端对着幽影号的船体指指点点，嘴里念念有词地爆出一连串星溯和叶子完全听不懂的技术术语。显然，这艘完美的战争机器，对他而言比任何社交活动都更具吸引力。 “我刚和洛克确认过，”尼尔德的声音里压抑着一丝难以置信的兴奋与激动，“他带着他的团队，花了十几个小时，把‘幽影号’里里外外、每个角落都检查了个遍。不知道是因为它被藏在基地的最底层，灵裔的探测器没能扫描到，还是它们出于某种我们不知道的原因，有意放过了这里……总之，这艘船的状态好得惊人，简直跟刚从生产线上下来没什么两样。能源核心满载，系统自检全绿，所有的功能模块都处于待机状态。这简直是……神迹。” 叶子环顾了一下这艘散发着无形压迫感的黑色巨舰，好看的眉毛挑了挑：“听起来是个天大的好消息。不过，我得问个比较煞风景的现实问题：我们这群乌合之众里，有谁会开这玩意儿吗？这可不是驾校里练手的那种大气层内穿梭机，我估计它的操作手册比一本百科全书还厚。” 尼尔德的嘴角勾起一抹混合着自信与神秘的微笑：“嗯……关于这一点，可能会让你有些意外。在加入‘α星防卫军’前，我曾经接受过为期两年的舰船驾驶训练，至于在哪参加的，你们先别管。”他用拇指指了指自己，语气中充满了不容置疑的自信，“总之，这次的逃离行动，就由我来担任临时船长。我知道你们可能会怀疑我的技术，毕竟我这个看起来就像大头兵的人不太可能会开飞船，但时间不等人，在这里多待一分钟，变数就多一分。总之，先登船吧，我们得尽快离开这个是非之地。” 星溯和叶子面面相觑，都从对方眼中看到了同款的惊讶，以及一丝“好吧，算你牛”的认同。事已至此，她们也没有别的选择。两人不再犹豫，紧跟在尼尔德身后，踏上了通往“幽影号”的登机舷梯。 飞船内部的空间比从外面看起来更为宽敞，设计风格是极致的简洁与高效，充满了冰冷的实用主义气息。柔和的照明光带从天花板和地板的缝隙中渗出，将主通道照得一片通明。一些先期抵达的幸存者已经三三两两地找地方坐下，他们或靠在墙边，或蜷缩在座椅上，每个人的脸上都交织着难以言状的疲惫、劫后余生的茫然，以及对未来的深深恐惧。 叶子轻车熟路地拉着星溯，灵巧地穿过沉默的人群，在船舱尾部一个相对僻静的角落里找到了两个空位坐下。这里靠近一扇小小的圆形舷窗，可惜现在舷窗外只能看到船库那单调的灰色墙壁。 “唉，”叶子长长地舒了一口气，整个人毫无形象地瘫在符合人体工学的座椅上，像一只被抽掉了骨头的猫，“现在回头想想，我真不该脑子一热就答应跟你来冒这个险。本来我只想当个普普通通的情报贩子，现在成了个黑户” 星溯无奈地笑了笑，侧过头看着她，眼神里满是歉意：“抱歉啦，叶子，把你卷进这么大的麻烦里……可惜，这次还是没能找到任何关于我父亲和我姐的线索。”她的话语里透着一丝难以掩饰的失落，但随即又想起了什么，眼睛倏地一亮，“哦，对了！你之前在我姐的房间里说要告诉我的，那个‘归家者’，到底是谁？” 叶子懒洋洋地掀起眼皮瞥了她一眼，似乎在从记忆的深处打捞一件很久远的事情。“啧，你不说我都快忘了……‘归家者’啊……”她坐直了些，神情变得有些微妙和复杂，“那家伙，严格来说，是一个外来者。或者用一个更酷、更中二的词来形容——一个天外来客。” “天外来客？”星溯的杏眼瞬间睁得溜圆，心跳都漏了半拍，“你的意思是……ta是……外星人？” “Bingo。”叶子俏皮地打了个响指，“一个不知道因为什么倒霉催的原因，稀里糊涂被卷到我们这个星系的可怜虫。一个……极度、极度渴望回家的人。她的名字，在她的母星语言里是什么意思我不知道，翻译....也翻译不出来是啥意思，所以我们这些和她打过交道的人，都叫她‘归家者’。而且，最关键的是，她和你那位天才老姐——星源，有着非同一般的学术合作关系。” “我姐？星源？”星溯彻底被这个消息震得外焦里嫩，感觉自己的世界观正在被一块块敲碎，“她……她还和外星人有关系？我怎么从来、从来都不知道？！” “那是因为你姐和你爸总想把你护在她那座象牙塔里，不想让你接触到这些水面下的东西。”叶子叹了口气，语气里带着几分感慨，“我们之前在你姐房间里看到的那份关于超空间引擎理论的文件，还记得吗？就是那张塞了小卡片的，我可以告诉你，那里面至少有一半的核心算法和理论基础，都出自‘归家者’之手。至于她们俩到底是怎么搭上线的，这个我就不清楚了，我的权限也不够。我只是因为执行一些特殊任务，和‘归家者’有过几次短暂的接触而已。” 叶子顿了顿，似乎在斟酌接下来的词句，然后又抛出了一个让星溯大脑直接宕机的重磅炸弹：“而且，这位‘归家者’女士，在财团的最高级别通缉令上都挂着号呢。罪名嘛……说出来你可能不信，相当的离谱，甚至有点行为艺术——在α星，非法贩卖纯净水。” 星溯的表情凝固了，她张了张嘴，却一个字也说不出来。“贩……贩卖纯净水？这……这算个啥子罪名？” “这罪名可大了去了。”叶子冷笑一声，眼神里充满了对财团的鄙夷，“在财团的统治下，所有基础生存资源，包括你呼吸的每一口空气和你喝的每一滴水，都经过了严格的‘标准化处理’和‘授权配给’。他们牢牢控制着所有星球的水源净化和分配渠道，以此来控制一切。而‘归家者’卖的，是未经财团‘认证’的、用她自己的技术净化出来的纯天然无污染纯净水。这在财团看来，无异于是在挑战他们统治的根基，是在挖他们的命根子。财团的霸道总裁逻辑基本上就是‘All your base are belong to us’（你们所有的基地都属于我们），这其中自然也包括了宇宙中的每一个H2O分子。所以，你懂的。” 星溯沉默了。她感觉自己对姐姐星源的认知，正在被彻底颠覆和重构。一个与神秘外星人合作研究禁忌科技，又与一个因为贩卖纯净水而被最高通缉的神秘人物有着千丝万缕联系的姐姐……在自己不知道的角落，她到底还隐藏了多少秘密？ …… 与此同时，幽影号的舰桥内。 尼尔德稳稳地坐在船长席上，修长的手指在面前巨大的全息触控屏幕上飞速舞动，下达着一道道指令。飞船已经如真正的幽灵般，悄无声息地升空，无声地穿透了α星那因战争而变得污浊厚重的大气层，平稳地驶入了深邃、静谧的宇宙。直到此刻，确认已经脱离了α星的引力范围和监控网络，他才关闭了舰船的“幽影”模式，解除了最高级别的通讯屏蔽。 瞬间，海量的数据流如同决堤的洪峰，涌入了舰载主脑的接收系统。各种延迟的官方通告、星系新闻、民间频道的加密信息流……如同瀑布般在屏幕上飞速刷新。尼尔德的目光冷静地扫过这些纷繁复杂的信息，进行着快速筛选。然而，当他看到一条被系统自动置顶的、来自“黎明之剑”内部最高加密频道的档案时，他的整个身体都僵住了，仿佛被瞬间冰封。 “黎明之剑最高指挥部联合声明：为应对财团暴政，捍卫sol系自由与和平，本组织正式与灵裔一族达成战略同盟协议” 标题的每一个字，都像一柄烧得通红的巨锤，狠狠地砸在他的脑海里，砸在他的信仰上。 怎么可能？ 他不明白，为什么自己赌上性命、背井离乡、一心反抗财团暴政、为了捍卫人类最后的尊严而战的组织，会与那些刚刚在α星上犯下滔天屠杀罪行的异族结盟？尽管α星上的许多人类并非无辜，他们也有部分人和灵裔有关系，但……但这算什么？他们都是被财团逼的，而且...与一群恶魔携手，去对抗另一个更庞大的恶魔吗？这与"零"最初的理想背道而驰！ 就在他大脑一片混乱，拼命地在后续文件中寻找更多信息，试图找到哪怕一丝一毫的证据来推翻这个荒谬绝伦的结论时，一个轻佻、妩媚，带着一丝慵懒猫性的声音，毫无征兆地在他身后响起。 “你好啊，尼尔德先生~” 尼尔德全身的汗毛在一瞬间根根倒竖！他受过的严酷训练让他做出了最快的反应，猛地从座椅上弹起并转身，只见一个婀娜的身影不知何时已经出现在他身后，正慵懒地斜靠在一台导航控制台上。 那是一个有着明显猫科动物特征的灵裔女性。一对毛茸茸的尖耳朵在柔顺的银色长发间微微抖动，一条同样是银色的长长尾巴在身后悠闲地画着圈。她穿着一身紧身的黑色作战服，勾勒出惊心动魄的曲线。最引人注目的是她那双眼睛，碧绿与金色交织的竖瞳，正饶有兴致地打量着他，仿佛在欣赏一件有趣的猎物。她的笑容甜美得如同蜜糖，却又透着一丝猫科动物捕猎前特有的狡黠与危险。 “初次见面，我是菲亚德娜，”她优雅地提起裙角，行了一个无可挑剔的屈膝礼，声音甜得发腻，“应我们至高无上的女皇陛下的命令，从今天起，我将成为灵裔在您这的的全权代言人，以及您的……贴心小助手哦，喵~” “嗡——”的一声微不可闻的轻响，尼尔德在零点一秒内就拔出了腰间配属的PG-7型高斯突击步枪，黑洞洞的枪口死死地对准了菲亚德娜的头颅。他的另一只手已经悬停在舰桥的紧急警报按钮上方，只需轻轻一按，整艘船都会响起刺耳的警报，所有战斗人员都会在第一时间冲向这里。 “你是怎么上来的，畜生！”他的声音因极致的愤怒而嘶哑，每一个字都像是从牙缝里挤出来的，充满了血腥味。 “哎呀，别那么心急嘛~火气这么大对皮肤不好哦。”菲亚德娜面对黑洞洞的枪口，却丝毫不见慌乱，甚至还伸出粉色的舌头，轻轻舔了舔自己的嘴唇，动作魅惑而致命，“至少，从现在开始，我们是为了同一个伟大目标而并肩奋斗的战友了，喵~” “闭嘴！你们这群在α星上屠杀了数百万人的刽子手！”尼尔德的手指已经搭在了扳机上，枪膛中的磁力线圈因为能量的极速汇聚而发出危险的低鸣。 “我们自然会为我们的行为承担相应的后果，但不是现在。”菲亚德娜的笑容收敛了一分，那双竖瞳中的戏谑褪去，变得锐利如刀，“此刻，我们拥有共同的敌人——财团。当然，你也可以现在就扣下扳机，不过我个人善意地提醒一下，就你这把小破枪，大概率只能给我挠痒痒。然后呢，我会有点生气，也许会一不小心，手滑一下，杀了这艘船上的所有人……” 她的目光仿佛穿透了厚重的舰桥舱壁，精准地“看”到了后面船舱里的那些幸存者。 “我知道我们对你们的同胞造成了无法弥补的损失，我也知道你们这群反抗军在过去给我们造成了多少麻烦。女皇陛下宅心仁厚，下令让我们不要伤害你们这些‘有理想、有抱负’的人。但是……”她话锋一转，声音变得冰冷而充满威胁，如同西伯利亚的寒风，“你后面的那群人，可不是‘黎明之剑’的正式成员哦。他们里面，有前阿尔法星防卫军的残兵，现在是你需要保护的幸存者同伴；还有两位……是从遥远的β星远道而来的客人。我杀了他们，应该没人会有意见吧？毕竟，他们可不在我们灵裔帝国和‘黎明之剑’的同盟协议保护范围之内，不是吗？” “（一句流利丝滑的β星粗口）！” 尼尔德的胸膛剧烈起伏，如同一个濒临极限的风箱。握枪的手臂因为愤怒和肌肉的过度紧绷而剧烈颤抖，但他最终还是缓缓地、极其不甘地放下了手中的武器。那支沉重的步枪垂下的那一刻，仿佛也抽走了他全身所有的力气和精神。 他不敢赌。 他不能拿船上那一百多条无辜的生命去赌。他是一名战士，保护平民是铭刻在他骨子里的天职。 菲亚德娜看到他屈服，脸上又恢复了那副甜美而胜利的笑容。她迈着优雅的猫步，款款走到尼尔德面前，距离近得可以让他清晰地闻到她身上传来的一股淡淡的、如同雨后初晴的森林般的异香。 “很好，看来我们达成了愉快的共识。”她伸出戴着黑色手套的纤细手指，轻轻拂过尼尔德步枪冰冷的枪身，动作暧昧而挑衅，然后抬起那双摄人心魄的眼睛，直视着他因屈辱而充血的双眸。 “那么现在，我们可以来好好聊聊正事了。前阿尔法星防卫军，第61‘风暴’师，75团，下士，尼尔德先生。或者……我该用一个更不为人知的身份来称呼您——‘黎明之剑’的高级指挥官，代号‘骑士’的先生？”')],-1)),n(s),n(r)])}const x=l(p,[["render",d]]);export{f as __pageData,x as default};
